{
  "name": "PalliativeAI - Clinical Decision Support System",
  "description": "A high-fidelity CDSS for palliative care nurses featuring ESAS-r, PPS v2 functional assessment, and NCCN-aligned logic for symptom management.",
  "requestFramePermissions": []
}

export type ACPStatus = 'DNR' | 'DNI' | 'Full Code' | 'Limited Intervention';

export interface SymptomScores {
  pain: number;
  tiredness: number;
  drowsiness: number;
  nausea: number;
  appetite: number;
  dyspnea: number;
  depression: number;
  anxiety: number;
  wellbeing: number;
}

export interface VitalSigns {
  heartRate: number;
  systolicBP: number;
  diastolicBP: number;
  respiratoryRate: number;
  oxygenSat: number;
  temperature: number;
}

export interface ComfortSigns {
  restlessness: boolean;
  secretions: boolean; // Death rattle
  agitation: boolean;
  facialGrimace: boolean;
}

export interface Patient {
  id: string;
  name: string;
  age: number;
  mrn: string;
  diagnosis: string;
  acp: ACPStatus;
  pps: number; // 0 to 100
  esas: SymptomScores;
  vitals: VitalSigns;
  comfort: ComfortSigns;
  history: Array<{
    date: string;
    esas: SymptomScores;
    pps: number;
  }>;
  status: 'Active' | 'Imminent Death' | 'Discharged' | 'Deceased';
}

export interface Intervention {
  title: string;
  description: string;
  priority: 'High' | 'Medium' | 'Low';
  category: 'Pharmacological' | 'Nursing' | 'Psychosocial';
}

import { SymptomScores, VitalSigns, Intervention, ComfortSigns } from '../types';

/**
 * Evaluates patient symptoms and vitals to provide clinically valid interventions
 * based on NCCN Palliative Care guidelines.
 */
export const evaluateStatus = (
  esas: SymptomScores,
  vitals: VitalSigns,
  comfort: ComfortSigns,
  pps: number
): Intervention[] => {
  const interventions: Intervention[] = [];

  // 1. Pain Management
  if (esas.pain >= 7) {
    interventions.push({
      title: "Acute Pain Crisis Protocol",
      description: "Administer breakthrough opioid dose immediately. Notify provider for potential PCA or rotation. Assess for bone pain (steroids) or neuropathic pain (adjuvants).",
      priority: 'High',
      category: 'Pharmacological'
    });
  } else if (esas.pain >= 4) {
    interventions.push({
      title: "Moderate Pain Management",
      description: "Review current around-the-clock analgesia. Ensure bowel regimen is in place. Non-pharmacological: Heat/Cold therapy, repositioning.",
      priority: 'Medium',
      category: 'Nursing'
    });
  }

  // 2. Dyspnea (Shortness of Breath) Logic
  if (esas.dyspnea >= 6) {
    if (vitals.oxygenSat < 90) {
      interventions.push({
        title: "Hypoxemic Dyspnea Intervention",
        description: "Apply O2 via nasal cannula (2-4L/min). Titrate to comfort, not just saturation. Consider low-dose morphine (2-5mg) for air hunger perception.",
        priority: 'High',
        category: 'Pharmacological'
      });
    } else {
      interventions.push({
        title: "Non-Hypoxemic Breathlessness",
        description: "Increase air movement with a cool fan. Positioning (High Fowlers). Guided relaxation. Oxygen may not be helpful here.",
        priority: 'Medium',
        category: 'Nursing'
      });
    }
  }

  // 3. Imminent Death Specifics (PPS < 20%)
  if (pps <= 20) {
    if (comfort.secretions) {
      interventions.push({
        title: "Respiratory Secretions (Death Rattle)",
        description: "Reposition to side-lying (drainage). Avoid deep suctioning (distressing). Consider anticholinergics (Glycopyrrolate or Hyoscine).",
        priority: 'High',
        category: 'Pharmacological'
      });
    }
    if (comfort.restlessness || comfort.agitation) {
      interventions.push({
        title: "Terminal Agitation Management",
        description: "Rule out full bladder or constipation. Administer Midazolam or Haloperidol per protocol. Maintain quiet, dimly lit environment.",
        priority: 'High',
        category: 'Pharmacological'
      });
    }
    interventions.push({
      title: "End-of-Life Comfort Care",
      description: "Discontinue non-essential medications (statins, vitamins). Focus on oral hygiene/swabs. Support family presence and 'final goodbyes'.",
      priority: 'High',
      category: 'Nursing'
    });
  }

  // 4. Psychosocial Support
  if (esas.anxiety >= 5 || esas.depression >= 5) {
    interventions.push({
      title: "Psychosocial Support Bundle",
      description: "Spiritual care/Chaplaincy referral. Therapeutic presence. Review for situational distress vs clinical depression.",
      priority: 'Medium',
      category: 'Psychosocial'
    });
  }

  return interventions;
};

import React, { createContext, useContext, useState, ReactNode } from 'react';
import { Patient } from '../types';

interface PatientContextType {
  patients: Patient[];
  selectedPatient: Patient | null;
  addPatient: (patient: Patient) => void;
  updatePatient: (id: string, updates: Partial<Patient>) => void;
  selectPatient: (id: string) => void;
}

const PatientContext = createContext<PatientContextType | undefined>(undefined);

export const PatientProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [patients, setPatients] = useState<Patient[]>([]);
  const [selectedPatientId, setSelectedPatientId] = useState<string | null>(null);

  const addPatient = (patient: Patient) => {
    setPatients(prev => [...prev, patient]);
    setSelectedPatientId(patient.id);
  };

  const updatePatient = (id: string, updates: Partial<Patient>) => {
    setPatients(prev => prev.map(p => p.id === id ? { ...p, ...updates } : p));
  };

  const selectPatient = (id: string) => {
    setSelectedPatientId(id);
  };

  const selectedPatient = patients.find(p => p.id === selectedPatientId) || null;

  return (
    <PatientContext.Provider value={{ patients, selectedPatient, addPatient, updatePatient, selectPatient }}>
      {children}
    </PatientContext.Provider>
  );
};

export const usePatients = () => {
  const context = useContext(PatientContext);
  if (!context) throw new Error("usePatients must be used within PatientProvider");
  return context;
};

import React, { useState } from 'react';
import { usePatients } from '../context/PatientContext';
import { Patient, ACPStatus } from '../types';
import { UserPlus, Save, ClipboardList } from 'lucide-react';

const AdmissionForm: React.FC<{ onComplete: () => void }> = ({ onComplete }) => {
  const { addPatient } = usePatients();
  const [formData, setFormData] = useState({
    name: '',
    age: '',
    mrn: '',
    diagnosis: '',
    acp: 'DNR' as ACPStatus
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const newPatient: Patient = {
      id: Math.random().toString(36).substr(2, 9),
      name: formData.name,
      age: parseInt(formData.age),
      mrn: formData.mrn,
      diagnosis: formData.diagnosis,
      acp: formData.acp,
      pps: 80,
      esas: {
        pain: 0, tiredness: 0, drowsiness: 0, nausea: 0,
        appetite: 0, dyspnea: 0, depression: 0, anxiety: 0, wellbeing: 0
      },
      vitals: {
        heartRate: 80, systolicBP: 120, diastolicBP: 80,
        respiratoryRate: 16, oxygenSat: 98, temperature: 36.6
      },
      comfort: {
        restlessness: false, secretions: false, agitation: false, facialGrimace: false
      },
      history: [],
      status: 'Active'
    };
    addPatient(newPatient);
    onComplete();
  };

  return (
    <div className="max-w-2xl mx-auto bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
      <div className="bg-teal-600 p-6 flex items-center gap-3 text-white">
        <UserPlus className="w-6 h-6" />
        <h2 className="text-xl font-bold">New Patient Admission</h2>
      </div>
      <form onSubmit={handleSubmit} className="p-8 space-y-6">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="space-y-1">
            <label className="text-sm font-semibold text-slate-600">Full Name</label>
            <input 
              required
              className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none"
              value={formData.name}
              onChange={e => setFormData({...formData, name: e.target.value})}
              placeholder="e.g. John Doe"
            />
          </div>
          <div className="space-y-1">
            <label className="text-sm font-semibold text-slate-600">MRN #</label>
            <input 
              required
              className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none"
              value={formData.mrn}
              onChange={e => setFormData({...formData, mrn: e.target.value})}
              placeholder="Medical Record Number"
            />
          </div>
          <div className="space-y-1">
            <label className="text-sm font-semibold text-slate-600">Age</label>
            <input 
              required
              type="number"
              className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none"
              value={formData.age}
              onChange={e => setFormData({...formData, age: e.target.value})}
            />
          </div>
          <div className="space-y-1">
            <label className="text-sm font-semibold text-slate-600">Advanced Care Plan (ACP)</label>
            <select 
              className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none"
              value={formData.acp}
              onChange={e => setFormData({...formData, acp: e.target.value as ACPStatus})}
            >
              <option value="DNR">DNR (Do Not Resuscitate)</option>
              <option value="DNI">DNI (Do Not Intubate)</option>
              <option value="Full Code">Full Code</option>
              <option value="Limited Intervention">Limited Intervention</option>
            </select>
          </div>
        </div>
        <div className="space-y-1">
          <label className="text-sm font-semibold text-slate-600">Primary Diagnosis</label>
          <textarea 
            required
            className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg focus:ring-2 focus:ring-teal-500 outline-none h-24"
            value={formData.diagnosis}
            onChange={e => setFormData({...formData, diagnosis: e.target.value})}
            placeholder="Document current disease state and stage..."
          />
        </div>
        <button 
          type="submit"
          className="w-full py-4 bg-teal-600 hover:bg-teal-700 text-white font-bold rounded-xl transition-all shadow-lg shadow-teal-100 flex items-center justify-center gap-2"
        >
          <Save className="w-5 h-5" />
          Complete Admission
        </button>
      </form>
    </div>
  );
};

export default AdmissionForm;

import React, { useState } from 'react';
import { createRoot } from 'react-dom/client';
import { PatientProvider, usePatients } from './context/PatientContext';
import AdmissionForm from './components/AdmissionForm';
import DailyAssessment from './components/DailyAssessment';
import ClinicalDashboard from './components/ClinicalDashboard';
import AfterCare from './components/AfterCare';
import { 
  Users, 
  UserPlus, 
  Activity, 
  LayoutDashboard, 
  HeartHandshake,
  Stethoscope
} from 'lucide-react';

const AppContent: React.FC = () => {
  const { patients, selectedPatient, selectPatient } = usePatients();
  const [activeTab, setActiveTab] = useState<'list' | 'admission' | 'assessment' | 'dashboard' | 'aftercare'>('list');

  const renderContent = () => {
    if (activeTab === 'list') {
      return (
        <div className="space-y-6">
          <div className="flex justify-between items-center">
            <h1 className="text-3xl font-bold text-slate-800">Patient Census</h1>
            <button 
              onClick={() => setActiveTab('admission')}
              className="bg-teal-600 text-white px-4 py-2 rounded-lg flex items-center gap-2 hover:bg-teal-700 transition-colors"
            >
              <UserPlus size={20} /> New Admission
            </button>
          </div>

          {patients.length === 0 ? (
            <div className="bg-white border-2 border-dashed border-slate-200 rounded-2xl p-12 text-center">
              <Users className="mx-auto text-slate-300 mb-4" size={48} />
              <p className="text-slate-500 font-medium">No patients in current census.</p>
              <button 
                onClick={() => setActiveTab('admission')}
                className="mt-4 text-teal-600 font-bold hover:underline"
              >
                Add your first patient to begin.
              </button>
            </div>
          ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
              {patients.map(p => (
                <div 
                  key={p.id}
                  onClick={() => { selectPatient(p.id); setActiveTab('dashboard'); }}
                  className={`p-6 rounded-2xl border-2 transition-all cursor-pointer hover:shadow-md ${
                    selectedPatient?.id === p.id ? 'border-teal-500 bg-teal-50/30' : 'border-white bg-white shadow-sm'
                  }`}
                >
                  <div className="flex justify-between items-start mb-4">
                    <h3 className="text-xl font-bold text-slate-800">{p.name}</h3>
                    <span className={`px-2 py-1 rounded text-xs font-bold ${
                      p.status === 'Imminent Death' ? 'bg-amber-100 text-amber-700' : 'bg-teal-100 text-teal-700'
                    }`}>
                      {p.status}
                    </span>
                  </div>
                  <div className="space-y-2 text-sm text-slate-600">
                    <p><strong>MRN:</strong> {p.mrn}</p>
                    <p><strong>PPS:</strong> {p.pps}%</p>
                    <p className="truncate"><strong>DX:</strong> {p.diagnosis}</p>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      );
    }

    if (activeTab === 'admission') return <AdmissionForm onComplete={() => setActiveTab('list')} />;
    if (!selectedPatient) return <div className="p-12 text-center text-slate-500">Please select a patient first.</div>;

    if (activeTab === 'assessment') return <DailyAssessment onComplete={() => setActiveTab('dashboard')} />;
    if (activeTab === 'dashboard') return <ClinicalDashboard />;
    if (activeTab === 'aftercare') return <AfterCare onComplete={() => setActiveTab('list')} />;

    return null;
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col md:flex-row">
      {/* Sidebar */}
      <nav className="w-full md:w-64 bg-white border-r border-slate-200 p-4 flex flex-col gap-2">
        <div className="flex items-center gap-2 px-4 py-6 mb-4">
          <div className="bg-teal-600 p-2 rounded-lg">
            <Stethoscope className="text-white" size={24} />
          </div>
          <span className="text-xl font-black text-slate-800 tracking-tight">PalliativeAI</span>
        </div>

        <NavButton active={activeTab === 'list'} onClick={() => setActiveTab('list')} icon={<Users size={20}/>} label="Census" />
        <NavButton active={activeTab === 'admission'} onClick={() => setActiveTab('admission')} icon={<UserPlus size={20}/>} label="Admission" />

        {selectedPatient && (
          <div className="mt-8 pt-8 border-t border-slate-100 space-y-2">
            <p className="px-4 text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-2">Patient Actions</p>
            <NavButton active={activeTab === 'assessment'} onClick={() => setActiveTab('assessment')} icon={<Activity size={20}/>} label="Assessment" />
            <NavButton active={activeTab === 'dashboard'} onClick={() => setActiveTab('dashboard')} icon={<LayoutDashboard size={20}/>} label="Dashboard" />
            <NavButton active={activeTab === 'aftercare'} onClick={() => setActiveTab('aftercare')} icon={<HeartHandshake size={20}/>} label="After Care" />
          </div>
        )}
      </nav>

      {/* Main Area */}
      <main className="flex-1 p-6 md:p-10 max-w-7xl mx-auto w-full">
        {renderContent()}
      </main>
    </div>
  );
};

const NavButton = ({ active, onClick, icon, label }: { active: boolean, onClick: () => void, icon: React.ReactNode, label: string }) => (
  <button 
    onClick={onClick}
    className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-medium transition-all ${
      active ? 'bg-teal-50 text-teal-700 shadow-sm shadow-teal-100/50' : 'text-slate-500 hover:bg-slate-50'
    }`}
  >
    {icon}
    {label}
  </button>
);

const rootElement = document.getElementById('root');
if (rootElement) {
  createRoot(rootElement).render(
    <PatientProvider>
      <AppContent />
    </PatientProvider>
  );
}

import React, { useState } from 'react';
import { usePatients } from '../context/PatientContext';
import { SymptomScores, VitalSigns, ComfortSigns } from '../types';
import { Activity, Thermometer, Wind, Save, HeartPulse, Droplets, Smile } from 'lucide-react';

const DailyAssessment: React.FC<{ onComplete: () => void }> = ({ onComplete }) => {
  const { selectedPatient, updatePatient } = usePatients();
  const [esas, setEsas] = useState<SymptomScores>(selectedPatient?.esas || {
    pain: 0, tiredness: 0, drowsiness: 0, nausea: 0, appetite: 0, dyspnea: 0, depression: 0, anxiety: 0, wellbeing: 0
  });
  const [pps, setPps] = useState(selectedPatient?.pps || 80);
  const [vitals, setVitals] = useState<VitalSigns>(selectedPatient?.vitals || {
    heartRate: 80, systolicBP: 120, diastolicBP: 80, respiratoryRate: 16, oxygenSat: 98, temperature: 36.6
  });
  const [comfort, setComfort] = useState<ComfortSigns>(selectedPatient?.comfort || {
    restlessness: false, secretions: false, agitation: false, facialGrimace: false
  });

  if (!selectedPatient) return null;

  const isImminent = pps <= 20;

  const handleSave = () => {
    updatePatient(selectedPatient.id, {
      esas,
      pps,
      vitals,
      comfort,
      status: pps <= 20 ? 'Imminent Death' : 'Active',
      history: [...selectedPatient.history, { date: new Date().toISOString(), esas, pps }]
    });
    onComplete();
  };

  const SymptomSlider = ({ label, value, field }: { label: string, value: number, field: keyof SymptomScores }) => (
    <div className="space-y-3 p-4 bg-white rounded-xl border border-slate-200">
      <div className="flex justify-between items-center">
        <label className="text-sm font-bold text-slate-700">{label}</label>
        <span className={`text-lg font-bold px-3 py-1 rounded-lg ${
          value >= 7 ? 'bg-red-100 text-red-600' : value >= 4 ? 'bg-amber-100 text-amber-600' : 'bg-teal-100 text-teal-600'
        }`}>
          {value}/10
        </span>
      </div>
      <input 
        type="range" min="0" max="10" step="1"
        className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-teal-600"
        value={value}
        onChange={e => setEsas({ ...esas, [field]: parseInt(e.target.value) })}
      />
    </div>
  );

  return (
    <div className="max-w-5xl mx-auto space-y-8">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h2 className="text-3xl font-black text-slate-800">Daily Assessment</h2>
          <p className="text-slate-500">Patient: {selectedPatient.name} (MRN: {selectedPatient.mrn})</p>
        </div>
        <button 
          onClick={handleSave}
          className="flex items-center gap-2 bg-teal-600 text-white px-8 py-3 rounded-xl font-bold hover:bg-teal-700 transition-all shadow-lg shadow-teal-100"
        >
          <Save size={20} /> Save Assessment
        </button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* ESAS Section */}
        <div className="lg:col-span-2 space-y-4">
          <div className="flex items-center gap-2 mb-2">
            <Smile className="text-teal-600" />
            <h3 className="text-xl font-bold text-slate-800">ESAS-r Symptoms</h3>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <SymptomSlider label="Pain" value={esas.pain} field="pain" />
            <SymptomSlider label="Tiredness" value={esas.tiredness} field="tiredness" />
            <SymptomSlider label="Drowsiness" value={esas.drowsiness} field="drowsiness" />
            <SymptomSlider label="Nausea" value={esas.nausea} field="nausea" />
            <SymptomSlider label="Appetite" value={esas.appetite} field="appetite" />
            <SymptomSlider label="Dyspnea" value={esas.dyspnea} field="dyspnea" />
            <SymptomSlider label="Depression" value={esas.depression} field="depression" />
            <SymptomSlider label="Anxiety" value={esas.anxiety} field="anxiety" />
            <SymptomSlider label="Wellbeing" value={esas.wellbeing} field="wellbeing" />
          </div>
        </div>

        {/* PPS and Contextual Section */}
        <div className="space-y-6">
          <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
            <div className="flex items-center justify-between mb-4">
              <h3 className="text-lg font-bold text-slate-800">Palliative Performance (PPS)</h3>
              <span className="text-2xl font-black text-teal-600">{pps}%</span>
            </div>
            <select 
              value={pps} 
              onChange={e => setPps(parseInt(e.target.value))}
              className="w-full p-3 bg-slate-50 border border-slate-200 rounded-lg outline-none focus:ring-2 focus:ring-teal-500"
            >
              {[100, 90, 80, 70, 60, 50, 40, 30, 20, 10].map(val => (
                <option key={val} value={val}>{val}% - {getPPSLabel(val)}</option>
              ))}
            </select>
          </div>

          {!isImminent ? (
            <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm space-y-4">
              <h3 className="text-lg font-bold text-slate-800 flex items-center gap-2">
                <HeartPulse className="text-teal-600" size={20}/> Vitals
              </h3>
              <div className="grid grid-cols-2 gap-4">
                <VitalInput label="HR" value={vitals.heartRate} onChange={v => setVitals({...vitals, heartRate: v})} />
                <VitalInput label="SBP" value={vitals.systolicBP} onChange={v => setVitals({...vitals, systolicBP: v})} />
                <VitalInput label="RR" value={vitals.respiratoryRate} onChange={v => setVitals({...vitals, respiratoryRate: v})} />
                <VitalInput label="O2%" value={vitals.oxygenSat} onChange={v => setVitals({...vitals, oxygenSat: v})} />
              </div>
            </div>
          ) : (
            <div className="bg-amber-50 p-6 rounded-2xl border border-amber-200 shadow-sm space-y-4">
              <h3 className="text-lg font-bold text-amber-800 flex items-center gap-2">
                <Droplets className="text-amber-600" size={20}/> Comfort Assessment
              </h3>
              <p className="text-xs text-amber-700 italic">Vitals burden reduced for end-of-life care.</p>
              <div className="space-y-3">
                <ComfortToggle label="Respiratory Secretions" active={comfort.secretions} onToggle={() => setComfort({...comfort, secretions: !comfort.secretions})} />
                <ComfortToggle label="Restlessness" active={comfort.restlessness} onToggle={() => setComfort({...comfort, restlessness: !comfort.restlessness})} />
                <ComfortToggle label="Terminal Agitation" active={comfort.agitation} onToggle={() => setComfort({...comfort, agitation: !comfort.agitation})} />
                <ComfortToggle label="Facial Grimacing" active={comfort.facialGrimace} onToggle={() => setComfort({...comfort, facialGrimace: !comfort.facialGrimace})} />
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

const getPPSLabel = (val: number) => {
  if (val >= 70) return "Normal Activity";
  if (val >= 40) return "Mainly Bed/Sit";
  if (val >= 20) return "Totally Bedbound";
  return "Imminent Death";
};

const VitalInput = ({ label, value, onChange }: { label: string, value: number, onChange: (v: number) => void }) => (
  <div className="space-y-1">
    <label className="text-[10px] font-bold text-slate-500 uppercase">{label}</label>
    <input 
      type="number"
      value={value}
      onChange={e => onChange(parseInt(e.target.value))}
      className="w-full p-2 bg-slate-50 border border-slate-200 rounded-lg text-sm font-bold focus:ring-1 focus:ring-teal-500 outline-none"
    />
  </div>
);

const ComfortToggle = ({ label, active, onToggle }: { label: string, active: boolean, onToggle: () => void }) => (
  <button 
    onClick={onToggle}
