import { SymptomScores, VitalSigns, Intervention, ComfortSigns } from '../types';

/**
 * ประเมินอาการและสัญญาณชีพเพื่อให้คำแนะนำการพยาบาลที่ถูกต้องตามหลักวิชาการ
 * อ้างอิงตามแนวทาง NCCN Palliative Care
 */
export const evaluateStatus = (
  esas: SymptomScores,
  vitals: VitalSigns,
  comfort: ComfortSigns,
  pps: number
): Intervention[] => {
  const interventions: Intervention[] = [];

  // 1. การจัดการความปวด
  if (esas.pain >= 7) {
    interventions.push({
      title: "โปรโตคอลจัดการความปวดวิกฤต",
      description: "ให้ยาแก้ปวดกลุ่ม Opioid สำหรับอาการปวดเฉียบพลันทันที รายงานแพทย์เพื่อพิจารณาปรับขนาดยาหรือเปลี่ยนช่องทางการให้ยา ประเมินลักษณะปวดกระดูกหรือปวดจากเส้นประสาทร่วมด้วย",
      priority: 'High',
      category: 'Pharmacological'
    });
  } else if (esas.pain >= 4) {
    interventions.push({
      title: "การจัดการความปวดระดับปานกลาง",
      description: "ทบทวนการให้ยาแก้ปวดตามรอบเวลา ตรวจสอบแผนการป้องกันอาการท้องผูก ใช้การบำบัดทางเลือก เช่น การจัดท่า หรือการประคบร้อน/เย็น",
      priority: 'Medium',
      category: 'Nursing'
    });
  }

  // 2. การจัดการอาการหายใจลำบาก (Dyspnea)
  if (esas.dyspnea >= 6) {
    if (vitals.oxygenSat < 90) {
      interventions.push({
        title: "การจัดการภาวะหายใจลำบากร่วมกับออกซิเจนต่ำ",
        description: "ให้ออกซิเจนผ่าน Nasal Cannula (2-4 ลิตร/นาที) ปรับตามความสุขสบายของผู้ป่วย พิจารณาใช้ Morphine ขนาดต่ำ (2-5 มก.) เพื่อลดอาการหิวกระหายอากาศ",
        priority: 'High',
        category: 'Pharmacological'
      });
    } else {
      interventions.push({
        title: "การจัดการอาการหายใจลำบาก (ออกซิเจนปกติ)",
        description: "เพิ่มการไหลเวียนอากาศด้วยพัดลม จัดท่าศีรษะสูง (High Fowlers) ฝึกการผ่อนคลาย การให้ออกซิเจนอาจไม่ช่วยลดอาการในกรณีนี้",
        priority: 'Medium',
        category: 'Nursing'
      });
    }
  }

  // 3. การดูแลระยะท้าย (PPS < 20%)
  if (pps <= 20) {
    if (comfort.secretions) {
      interventions.push({
        title: "การจัดการเสมหะในลำคอ (Death Rattle)",
        description: "จัดท่านอนตะแคงเพื่อระบายเสมหะ หลีกเลี่ยงการดูดเสมหะที่ลึกเกินไปเพราะจะทำให้ผู้ป่วยทรมาน พิจารณาใช้ยาในกลุ่ม Anticholinergics",
        priority: 'High',
        category: 'Pharmacological'
      });
    }
    if (comfort.restlessness || comfort.agitation) {
      interventions.push({
        title: "การจัดการภาวะสับสนวุ่นวายระยะสุดท้าย",
        description: "หาสาเหตุที่แก้ไขได้ เช่น กระเพาะปัสสาวะเต็มหรือท้องผูก ให้ยาตามโปรโตคอล (Midazolam หรือ Haloperidol) จัดสิ่งแวดล้อมให้เงียบสงบและแสงสว่างน้อย",
        priority: 'High',
        category: 'Pharmacological'
      });
    }
    interventions.push({
      title: "การดูแลเพื่อความสุขสบายระยะสุดท้าย",
      description: "หยุดยาที่ไม่จำเป็นทั้งหมด เน้นการทำความสะอาดช่องปาก ให้ความสำคัญกับการอยู่ร่วมกับครอบครัวและการสั่งเสียครั้งสุดท้าย",
      priority: 'High',
      category: 'Nursing'
    });
  }

  // 4. การสนับสนุนด้านจิตสังคม
  if (esas.anxiety >= 5 || symptomsIncludePsychological(esas)) {
    interventions.push({
      title: "การดูแลด้านจิตใจและจิตวิญญาณ",
      description: "ประสานงานทีมดูแลด้านจิตวิญญาณหรือนักสังคมสงเคราะห์ รับฟังอย่างตั้งใจ และประเมินความต้องการในการประกอบพิธีกรรมตามความเชื่อ",
      priority: 'Medium',
      category: 'Psychosocial'
    });
  }

  return interventions;
};

const symptomsIncludePsychological = (esas: SymptomScores) => esas.anxiety >= 5 || esas.depression >= 5;

