import { SymptomScores, VitalSigns, Intervention, ComfortSigns } from '../types';

/**
 * AI Screening: ตรวจสอบว่ากลุ่มโรคเข้าเกณฑ์ประคับประคองหรือไม่
 */
export const checkPalliativeCriteria = (diagnosis: string): { isPalliative: boolean; reason: string; recommendedTool: string[] } => {
  const diag = diagnosis.toLowerCase();

  // กลุ่มโรคมะเร็ง
  if (diag.includes('cancer') || diag.includes('มะเร็ง') || diag.includes('malignant') || diag.includes('tumor')) {
    return {
      isPalliative: true,
      reason: "ผู้ป่วยกลุ่มโรคมะเร็งระยะแพร่กระจายหรือที่ไม่สามารถรักษาให้หายขาดได้ เข้าเกณฑ์การดูแลแบบประคับประคอง",
      recommendedTool: ["ESAS-r (ประเมินอาการ)", "PPS v2 (ประเมินสมรรถภาพ)"]
    };
  }

  // กลุ่มโรคอวัยวะล้มเหลวเรื้อรัง
  if (diag.includes('heart failure') || diag.includes('copd') || diag.includes('ckd') || diag.includes('cirrhosis') || diag.includes('หัวใจล้มเหลว') || diag.includes('ตับแข็ง')) {
    return {
      isPalliative: true,
      reason: "ผู้ป่วยกลุ่มโรคเรื้อรังระยะสุดท้าย (End-stage organ failure) มีความซับซ้อนของอาการสูง",
      recommendedTool: ["ESAS-r", "PPS v2", "Katz ADL"]
    };
  }

  // กลุ่มโรคสมองเสื่อม/ระบบประสาท
  if (diag.includes('dementia') || diag.includes('als') || diag.includes('stroke') || diag.includes('สมองเสื่อม') || diag.includes('หลอดเลือดสมอง')) {
    return {
      isPalliative: true,
      reason: "โรคทางระบบประสาทที่เสื่อมถอยอย่างต่อเนื่อง จำเป็นต้องวางแผนการดูแลล่วงหน้า (ACP)",
      recommendedTool: ["PPS v2", "PainAD (หากสื่อสารไม่ได้)"]
    };
  }

  return {
    isPalliative: false,
    reason: "ไม่พบข้อมูลที่ชัดเจนว่าเข้าเกณฑ์ประคับประคองขั้นรุนแรง อย่างไรก็ตามสามารถให้การดูแลตามอาการได้",
    recommendedTool: ["การประเมินอาการทั่วไป"]
  };
};

/**
 * AI Care Guidance: คำแนะนำการจัดการอาการเชิงลึก
 */
export const evaluateStatus = (
  esas: SymptomScores,
  vitals: VitalSigns,
  comfort: ComfortSigns,
  pps: number
): Intervention[] => {
  const interventions: Intervention[] = [];

  // 1. จัดการความปวด (Pain)
  if (esas.pain >= 7) {
    interventions.push({
      title: "AI แนะนำ: จัดการความปวดวิกฤต",
      description: "ประเมิน Pain Score ทุก 1 ชม. บริหารยา Breakthrough dose ตามแผนการรักษา และสังเกตอาการง่วงซึม/หายใจช้าจากการใช้ยา Opioid",
      priority: 'High',
      category: 'Pharmacological'
    });
  }

  // 2. จัดการหายใจลำบาก (Dyspnea)
  if (esas.dyspnea >= 6) {
    interventions.push({
      title: "AI แนะนำ: ลดอาการหิวกระหายอากาศ",
      description: "ใช้พัดลมเป่าหน้า (Cool fan) จัดท่าศีรษะสูง 45-90 องศา หาก O2 Sat < 90% ให้ Oxygen 2-4 LPM พิจารณา Morphine 2-5mg PO/SC เพื่อลดความรู้สึกเหนื่อย",
      priority: 'High',
      category: 'Nursing'
    });
  }

  // 3. ระยะใกล้เสียชีวิต (Active Dying)
  if (pps <= 20) {
    if (comfort.secretions) {
      interventions.push({
        title: "AI แนะนำ: จัดการเสียงเสมหะในลำคอ",
        description: "จัดท่านอนตะแคง (Side-lying) อธิบายให้ญาติเข้าใจว่าเป็นกลไกธรรมชาติ ไม่ควรดูดเสมหะ (Suction) เพราะจะเพิ่มความทรมาน",
        priority: 'High',
        category: 'Nursing'
      });
    }
    interventions.push({
      title: "AI แนะนำ: การดูแลด้านจิตใจระยะสุดท้าย",
      description: "เปิดโอกาสให้ครอบครัวได้สัมผัสตัวผู้ป่วย บอกลา และอนุญาตให้ผู้ป่วยจากไปอย่างสงบ (Permission to go)",
      priority: 'Medium',
      category: 'Psychosocial'
    });
  }

  return interventions;
};

import React, { useState, useEffect } from 'react';
