const AdmissionForm: React.FC<{ onComplete: () => void }> = ({ onComplete }) => {
  const { addPatient } = usePatients();
  const [formData, setFormData] = useState({
    name: '', age: '', mrn: '', diagnosis: '', acp: 'DNR' as ACPStatus
  });

  const [screening, setScreening] = useState<{ isPalliative: boolean; reason: string; recommendedTool: string[] } | null>(null);

  // AI Screening Effect
  useEffect(() => {
    if (formData.diagnosis.length > 3) {
      const result = checkPalliativeCriteria(formData.diagnosis);
      setScreening(result);
    } else {
      setScreening(null);
    }
  }, [formData.diagnosis]);

  const handleSubmit = (e: React.FormEvent) => {
