            <textarea required className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-teal-500 h-24" value={formData.diagnosis} onChange={e => setFormData({...formData, diagnosis: e.target.value})} placeholder="เช่น มะเร็งปอดระยะที่ 4 หรือ End-stage heart failure..." />
