import { SymptomScores, VitalSigns, ComfortSigns, AIRecommendation } from '../types';

/**
 * AI Screening & Tool Recommendation
 */
export const analyzePalliativeCriteria = (diagnosis: string) => {
  const diag = diagnosis.toLowerCase();
  const isPalliative = diag.match(/(cancer|มะเร็ง|failure|ล้มเหลว|end stage|stage 4|copd|ckd|cirrhosis|dementia|สมองเสื่อม|stroke)/i);

  return {
    isPalliative: !!isPalliative,
    suggestedTools: isPalliative ? ["ESAS-r", "PPS v2", "ACP Discussion"] : ["General Assessment"],
    reason: isPalliative ? "เข้าเกณฑ์ผู้ป่วยโรคที่คุกคามต่อชีวิต (Life-limiting illness)" : "ไม่พบเกณฑ์ประคับประคองที่ชัดเจน"
  };
};

/**
 * AI Assisted Care Guidance based on 6 Competencies (Maharaj Hospital Standard)
 */
export const getAIRecommendations = (
  esas: SymptomScores,
  pps: number,
  comfort: ComfortSigns
): AIRecommendation[] => {
  const recs: AIRecommendation[] = [];

  // สมรรถนะที่ 1: การจัดการดูแลทางกายและจิตสังคม
  if (esas.pain >= 7 || esas.dyspnea >= 6) {
    recs.push({
      competency: "สมรรถนะที่ 1 (Clinical Management)",
      title: "จัดการอาการรบกวนทางกายวิกฤต",
      action: "แยกแยะปัญหาและระบุเหตุผลของอาการ (ร่างกาย/จิตใจ) ให้ยาตามแผนและประเมินซ้ำทุก 1 ชม. ตามมาตรฐานความปวด/เหนื่อย",
      priority: 'High'
    });
  }

  // สมรรถนะที่ 2: การเสริมสร้างพลังอำนาจ (Empowerment)
  if (pps <= 40) {
    recs.push({
      competency: "สมรรถนะที่ 2 (Empowerment)",
      title: "เสริมสร้างพลังอำนาจผู้ป่วยและญาติ",
      action: "กระตุ้นให้ญาติค้นพบและยอมรับเหตุการณ์ที่จะเกิดขึ้นจริงด้านอารมณ์และสติปัญญา เพื่อเตรียมความพร้อมในการดูแล",
      priority: 'Medium'
    });
  }

  // สมรรถนะที่ 3: การให้คำปรึกษาเชิงลึก
  if (esas.anxiety >= 5 || esas.depression >= 5) {
    recs.push({
      competency: "สมรรถนะที่ 3 (Counseling)",
      title: "การให้คำปรึกษาเชิงลึก",
      action: "ใช้ทักษะการใส่ใจและการฟังอย่างตั้งใจ (Active Listening) เปิดพื้นที่ให้ผู้ป่วยระบายความกังวลและใช้ความเงียบอย่างเหมาะสม",
      priority: 'High'
    });
  }

  // สมรรถนะที่ 4: จริยธรรมและกฎหมาย
  recs.push({
    competency: "สมรรถนะที่ 4 (Ethics)",
    title: "จริยธรรมและเจตจำนงล่วงหน้า",
    action: "ทบทวนการแสดงเจตจำนงล่วงหน้า (Living Will) และเคารพการตัดสินใจเลือกการรักษาตามหลักจริยธรรม (Autonomy)",
    priority: 'Medium'
  });

  // กรณี Imminent Death (สมรรถนะที่ 1 เพิ่มเติม)
  if (pps <= 20 && comfort.secretions) {
    recs.push({
      competency: "สมรรถนะที่ 1 (EOL Care)",
      title: "การดูแลระยะท้าย (Death Rattle)",
      action: "จัดท่านอนตะแคงเพื่อระบายเสมหะ ลดการดูดเสมหะที่รุนแรงเพื่อคงไว้ซึ่งศักดิ์ศรีและคุณภาพชีวิต",
      priority: 'High'
    });
  }

  return recs;
};

