const getCompetencyIcon = (comp: string) => {
  if (comp.includes('1')) return <Activity className="text-red-500" />;
  if (comp.includes('2')) return <Compass className="text-teal-500" />;
  if (comp.includes('3')) return <Heart className="text-purple-500" />;
  if (comp.includes('4')) return <Scale className="text-amber-500" />;
  if (comp.includes('5')) return <Users className="text-blue-500" />;
  return <Brain className="text-slate-400" />;
};

const MetricBar = ({ label, value, max = 10, color }: { label: string, value: number, max?: number, color: string }) => (
  <div className="space-y-2">
    <div className="flex justify-between text-xs font-bold text-slate-500">
      <span>{label}</span>
      <span>{value}/{max}</span>
    </div>
    <div className="h-2 w-full bg-slate-100 rounded-full overflow-hidden">
      <div 
        className={`h-full ${color} transition-all duration-500`} 
        style={{ width: `${(value / max) * 100}%` }}
      />
    </div>
  </div>
);

export default ClinicalDashboard;

