                <VitalInput label="ชีพจร (HR)" value={vitals.heartRate} onChange={v => setVitals({...vitals, heartRate: v})} />
                <VitalInput label="ความดัน (SBP)" value={vitals.systolicBP} onChange={v => setVitals({...vitals, systolicBP: v})} />
                <VitalInput label="หายใจ (RR)" value={vitals.respiratoryRate} onChange={v => setVitals({...vitals, respiratoryRate: v})} />
                <VitalInput label="ออกซิเจน (O2%)" value={vitals.oxygenSat} onChange={v => setVitals({...vitals, oxygenSat: v})} />
