import { SymptomScores, VitalSigns, ComfortSigns, AIRecommendation } from '../types';

/**
 * AI Screening & Tool Recommendation
 */
export const analyzePalliativeCriteria = (diagnosis: string) => {
  const diag = diagnosis.toLowerCase();
  const isPalliative = diag.match(/(cancer|มะเร็ง|failure|ล้มเหลว|end stage|stage 4|copd|ckd|cirrhosis|dementia|สมองเสื่อม|stroke)/i);

  return {
    isPalliative: !!isPalliative,
    suggestedTools: isPalliative ? ["ESAS-r", "PPS v2", "ACP Discussion"] : ["General Assessment"],
    reason: isPalliative ? "เข้าเกณฑ์ผู้ป่วยโรคที่คุกคามต่อชีวิต (Life-limiting illness)" : "ไม่พบเกณฑ์ประคับประคองที่ชัดเจน"
  };
};

/**
 * AI แนะนำความถี่ในการประเมินอาการ
 */
export const getAssessmentFrequency = (esas: SymptomScores, pps: number): { interval: string; description: string; urgency: 'high' | 'medium' | 'low' } => {
  const maxSymptom = Math.max(esas.pain, esas.dyspnea, esas.anxiety);

  if (maxSymptom >= 7 || pps <= 20) {
    return { 
      interval: "ทุก 1-2 ชั่วโมง", 
      description: "ผู้ป่วยมีอาการรุนแรงหรืออยู่ในระยะวิกฤต ต้องการการเฝ้าระวังอย่างใกล้ชิด",
      urgency: 'high'
    };
  }

  if (maxSymptom >= 4 || pps <= 50) {
    return { 
      interval: "ทุก 4 ชั่วโมง", 
      description: "อาการปานกลาง ควรประเมินซ้ำตามรอบเวรและเมื่อมีการให้ยาควบคุมอาการ",
      urgency: 'medium'
    };
  }

  return { 
    interval: "ทุก 8-12 ชั่วโมง", 
    description: "อาการคงที่ สามารถประเมินตามรอบการรับส่งเวรปกติ",
    urgency: 'low'
  };
};

/**
 * AI Assisted Care Guidance based on 6 Competencies (Maharaj Hospital Standard)
 */
export const getAIRecommendations = (
  esas: SymptomScores,
  pps: number,
  comfort: ComfortSigns
): AIRecommendation[] => {
  const recs: AIRecommendation[] = [];

  // สมรรถนะที่ 1: การจัดการดูแลทางกายและจิตสังคม
  if (esas.pain >= 7 || esas.dyspnea >= 6) {
    recs.push({
      competency: "สมรรถนะที่ 1 (Clinical Management)",
      title: "จัดการอาการรบกวนทางกายวิกฤต",
      action: "แยกแยะปัญหาและระบุเหตุผลของอาการ (ร่างกาย/จิตใจ) ให้ยาตามแผนและประเมินซ้ำอย่างน้อยทุก 1 ชม.",
      priority: 'High'
    });
  }

  // สมรรถนะที่ 2: การเสริมสร้างพลังอำนาจ (Empowerment)
  if (pps <= 40) {
    recs.push({
      competency: "สมรรถนะที่ 2 (Empowerment)",
      title: "เตรียมความพร้อมครอบครัว",
      action: "กระตุ้นให้ญาติค้นพบและยอมรับเหตุการณ์ที่จะเกิดขึ้นจริงด้านอารมณ์และสติปัญญา",
      priority: 'Medium'
    });
  }

  // สมรรถนะที่ 3: การให้คำปรึกษาเชิงลึก
  if (esas.anxiety >= 5 || esas.depression >= 5) {
    recs.push({
      competency: "สมรรถนะที่ 3 (Counseling)",
      title: "ประคับประคองด้านจิตใจ",
      action: "ใช้ทักษะการฟังอย่างตั้งใจ (Active Listening) และความเงียบอย่างเหมาะสม",
      priority: 'High'
    });
  }

  // สมรรถนะที่ 4: จริยธรรมและกฎหมาย
  recs.push({
    competency: "สมรรถนะที่ 4 (Ethics)",
    title: "จริยธรรมและเจตจำนงล่วงหน้า",
    action: "ทบทวน Living Will และเคารพการตัดสินใจเลือกการรักษา (Autonomy)",
    priority: 'Medium'
  });

  // กรณี Imminent Death (สมรรถนะที่ 1 เพิ่มเติม)
  if (pps <= 20 && comfort.secretions) {
    recs.push({
      competency: "สมรรถนะที่ 1 (EOL Care)",
      title: "จัดการ Death Rattle",
      action: "จัดท่านอนตะแคง ลดการดูดเสมหะที่รุนแรงเพื่อความสุขสบายสูงสุด",
      priority: 'High'
    });
  }

  return recs;
};

