const getPPSLabel = (val: number) => {
  if (val >= 70) return "ช่วยเหลือตัวเองได้ดี กิจกรรมปกติ";
  if (val >= 40) return "ส่วนใหญ่นั่งหรือนอน ต้องการความช่วยเหลือบ้าง";
  if (val >= 20) return "นอนบนเตียงตลอด ต้องการการดูแลเต็มรูปแบบ";
  return "ระยะใกล้เสียชีวิต การทำงานของร่างกายลดลงมาก";
};

