            <input 
              required 
              placeholder="เช่น 10A, 201/1"
              className="w-full p-5 bg-slate-50 border border-slate-100 rounded-3xl outline-none focus:ring-4 focus:ring-sky-100 focus:bg-white text-xl font-black text-slate-800 transition-all" 
              value={formData.bedNumber} 
              onChange={e => setFormData({...formData, bedNumber: e.target.value})} 
            />
          </div>

          <div className="space-y-2">
            <div className="flex justify-between items-center px-1">
              <label className="text-sm font-bold text-slate-500 uppercase tracking-widest">การวินิจฉัย (Diagnosis)</label>
              <div className="flex items-center gap-1 text-[10px] text-sky-500 font-bold group cursor-help">
                <HelpCircle size={12} />
                <span>รองรับ AML, ALL, HF, ไตวาย ฯลฯ</span>
              </div>
            </div>
            <textarea 
              required 
              className="w-full p-5 bg-slate-50 border border-slate-100 rounded-3xl outline-none focus:ring-4 focus:ring-sky-100 focus:bg-white h-32 text-lg font-medium transition-all" 
              value={formData.diagnosisDetail} 
              onChange={e => setFormData({...formData, diagnosisDetail: e.target.value})} 
              placeholder="ใส่ชื่อโรค ตัวย่อ (เช่น AML, HF) หรืออาการสำคัญ..." 
            />
          </div>

          <div className="space-y-2">
            <label className="text-sm font-bold text-slate-500 uppercase tracking-widest px-1">แผนการดูแล (ACP)</label>
            <select 
              className="w-full p-5 bg-slate-50 border border-slate-100 rounded-3xl outline-none focus:ring-4 focus:ring-sky-100 focus:bg-white text-lg font-bold transition-all appearance-none cursor-pointer"
              value={formData.acp}
              onChange={e => setFormData({...formData, acp: e.target.value as ACPStatus})}
            >
              <option value="DNR">DNR (Do Not Resuscitate)</option>
              <option value="Full Code">Full Code</option>
              <option value="Limited Intervention">Limited Intervention</option>
            </select>
          </div>

          <button type="submit" className="w-full py-5 bg-sky-600 hover:bg-sky-700 text-white font-black text-lg rounded-3xl shadow-xl shadow-sky-100 transition-all hover:scale-[1.02] active:scale-95 flex items-center justify-center gap-3">
            <Save className="w-6 h-6" /> บันทึกและวิเคราะห์เคส
          </button>
        </form>
      </div>

      <div className="space-y-6">
        {/* AI Smart Insight Panel - Peaceful Yellow Theme */}
        <div className="bg-amber-50 p-8 rounded-[40px] border border-amber-100 shadow-sm relative overflow-hidden">
          <div className="absolute top-0 right-0 p-6 text-amber-200/50">
            <Sparkles size={48} />
          </div>
          <div className="flex items-center gap-3 mb-6">
            <div className="p-2 bg-white rounded-xl shadow-sm">
              <Brain className="text-amber-600" size={24} />
            </div>
            <h3 className="font-black text-lg text-amber-900 tracking-tight">AI Smart Insight</h3>
          </div>

          {screening ? (
            <div className="space-y-6">
              <div className={`p-5 rounded-3xl flex items-start gap-3 bg-white border ${screening.isPalliative ? 'border-sky-200 text-sky-900' : 'border-slate-100 text-slate-600'}`}>
                {screening.isPalliative ? <CheckCircle className="mt-1 text-sky-500" size={20}/> : <AlertCircle className="mt-1 text-amber-400" size={20}/>}
                <div className="text-sm">
                  <p className="font-black text-base">{screening.isPalliative ? 'พบเกณฑ์ประคับประคอง' : 'ตรวจพบอาการทั่วไป'}</p>
                  <p className="font-medium opacity-70 mt-1 leading-relaxed">{screening.reason}</p>
                </div>
              </div>

              <div className="space-y-3">
                <p className="text-[10px] font-black text-amber-700 uppercase tracking-[0.2em]">เครื่องมือประเมินที่แนะนำ:</p>
                <div className="flex flex-wrap gap-2">
                  {screening.suggestedTools.map((t: string) => (
                    <span key={t} className="px-4 py-2 bg-white text-sky-700 rounded-2xl text-[11px] font-black border border-amber-100/50 shadow-sm">{t}</span>
                  ))}
                </div>
              </div>
            </div>
          ) : (
            <div className="py-10 text-center space-y-4">
              <div className="w-16 h-16 bg-white/50 rounded-full flex items-center justify-center mx-auto border border-amber-100 border-dashed">
                <Brain size={32} className="text-amber-300" />
              </div>
              <p className="text-amber-700/50 text-sm font-bold italic">ใส่ชื่อโรคเพื่อเริ่มการวิเคราะห์...</p>
            </div>
          )}
        </div>

        <div className="bg-white p-8 rounded-[40px] border border-slate-50 text-slate-400 text-xs font-medium leading-relaxed">
          <p>ระบบจะทำการคัดกรองอัตโนมัติจากฐานข้อมูลสมรรถนะการพยาบาล Maharaj Standard โดยรองรับคำย่อสากลเพื่อให้คุณทำงานได้รวดเร็วขึ้น</p>
        </div>
      </div>
    </div>
  );
};

export default AdmissionForm;

import React, { useState } from 'react';
import { createRoot } from 'react-dom/client';
import { PatientProvider, usePatients } from './context/PatientContext';
import AdmissionForm from './components/AdmissionForm';
import DailyAssessment from './components/DailyAssessment';
import ClinicalDashboard from './components/ClinicalDashboard';
import AfterCare from './components/AfterCare';
import { 
  Users, 
  UserPlus, 
  Activity, 
  LayoutDashboard, 
  HeartHandshake,
  Stethoscope,
  ChevronRight,
  Sparkles
} from 'lucide-react';

/**
 * Fix: Added missing NavButton component for sidebar navigation
 */
interface NavButtonProps {
  active: boolean;
  onClick: () => void;
  icon: React.ReactNode;
  label: string;
}

const NavButton: React.FC<NavButtonProps> = ({ active, onClick, icon, label }) => (
  <button 
    onClick={onClick}
    className={`flex items-center gap-4 px-6 py-5 rounded-[26px] transition-all font-black text-lg w-full text-left ${
      active 
      ? 'bg-white text-sky-900 shadow-xl shadow-sky-200/50 translate-x-2' 
      : 'text-sky-900/40 hover:text-sky-900 hover:bg-white/50'
    }`}
  >
    <div className={`${active ? 'text-sky-600' : 'text-sky-900/30'}`}>
      {icon}
    </div>
    {label}
  </button>
);

const AppContent: React.FC = () => {
  const { patients, selectedPatient, selectPatient } = usePatients();
  const [activeTab, setActiveTab] = useState<'list' | 'admission' | 'assessment' | 'dashboard' | 'aftercare'>('list');

  const renderContent = () => {
    if (activeTab === 'list') {
      return (
        <div className="space-y-12 animate-in fade-in slide-in-from-bottom-4 duration-700">
          <div className="flex justify-between items-end">
            <div>
              <div className="flex items-center gap-3 mb-2">
                <Sparkles size={24} className="text-sky-500" />
                <span className="text-[10px] font-black uppercase tracking-[0.4em] text-sky-600/60">Digital Ward Management</span>
              </div>
              <h1 className="text-6xl font-black text-slate-900 tracking-tighter">ผังเตียงผู้ป่วย</h1>
              <p className="text-slate-400 font-bold mt-2 text-lg">หอผู้ป่วยประคับประคอง มาตรฐาน Maharaj CDSS</p>
            </div>
            <button 
              onClick={() => setActiveTab('admission')}
              className="bg-sky-600 text-white px-10 py-5 rounded-[26px] font-black text-lg flex items-center gap-3 hover:bg-sky-700 transition-all shadow-2xl shadow-sky-100 hover:scale-[1.05] active:scale-95"
            >
              <UserPlus size={24} /> รับเคสใหม่
            </button>
          </div>

          {patients.length === 0 ? (
            <div className="bg-white border-2 border-dashed border-slate-100 rounded-[56px] p-40 text-center shadow-sm">
              <div className="w-28 h-28 bg-sky-50 text-sky-200 rounded-full flex items-center justify-center mx-auto mb-10 transition-transform hover:rotate-12">
                <Users size={56} />
              </div>
              <p className="text-slate-400 font-black text-2xl mb-8">ไม่มีข้อมูลผู้ป่วยในระบบ</p>
              <button 
                onClick={() => setActiveTab('admission')}
                className="text-sky-600 font-black text-xl hover:text-sky-700 transition-all inline-flex items-center gap-2 group"
              >
                เพิ่มเตียงแรกของคุณ <ChevronRight className="group-hover:translate-x-2 transition-transform" />
              </button>
            </div>
          ) : (
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-10">
              {patients.map(p => (
                <div 
                  key={p.id}
                  onClick={() => { selectPatient(p.id); setActiveTab('dashboard'); }}
                  className={`group relative p-12 rounded-[56px] border transition-all cursor-pointer ${
                    selectedPatient?.id === p.id 
                    ? 'border-sky-500 bg-white shadow-2xl shadow-sky-100 scale-[1.08] z-10' 
                    : 'border-white bg-white shadow-sm hover:shadow-2xl hover:border-slate-100'
                  }`}
                >
                  <div className={`w-16 h-16 rounded-3xl flex items-center justify-center text-white font-black text-3xl mb-8 transition-transform group-hover:rotate-6 ${
                    p.status === 'Imminent Death' ? 'bg-red-500 shadow-lg shadow-red-100' : 'bg-sky-900 shadow-lg shadow-sky-100'
                  }`}>
                    {p.bedNumber}
                  </div>
                  <div className="space-y-6">
                    <div className="flex justify-between items-end">
                      <p className="text-[10px] font-black text-slate-300 uppercase tracking-[0.3em]">PPS Status</p>
                      <p className={`text-4xl font-black ${p.pps <= 30 ? 'text-red-500' : 'text-slate-900'}`}>{p.pps}%</p>
                    </div>
                    <div className="h-2 w-full bg-slate-50 rounded-full overflow-hidden">
                      <div className={`h-full transition-all duration-1500 ${p.pps <= 30 ? 'bg-red-500' : 'bg-sky-500'}`} style={{ width: `${p.pps}%` }}></div>
                    </div>
                  </div>
                  <div className="mt-10 flex items-center justify-between">
                    <span className={`px-5 py-2 rounded-full text-[10px] font-black uppercase tracking-[0.2em] border ${
                      p.status === 'Imminent Death' ? 'bg-red-50 text-red-600 border-red-100' : 'bg-sky-50 text-sky-700 border-sky-100'
                    }`}>
                      {p.status === 'Active' ? 'Stable' : 'Imminent'}
                    </span>
                    <ChevronRight size={20} className="text-slate-200 group-hover:text-sky-500 transition-colors" />
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      );
    }

    if (activeTab === 'admission') return <AdmissionForm onComplete={() => setActiveTab('list')} />;
    if (!selectedPatient) return <div className="p-40 text-center text-slate-300 font-black text-3xl italic">กรุณาเลือกเตียงที่ต้องการดูแล</div>;

    if (activeTab === 'assessment') return <DailyAssessment onComplete={() => setActiveTab('dashboard')} />;
    if (activeTab === 'dashboard') return <ClinicalDashboard />;
    if (activeTab === 'aftercare') return <AfterCare onComplete={() => setActiveTab('list')} />;

    return null;
  };

  return (
    <div className="min-h-screen bg-white flex flex-col md:flex-row overflow-hidden">
      {/* Sidebar - Peaceful Light Blue Theme */}
      <nav className="w-full md:w-96 bg-sky-50/50 border-r border-sky-100 p-10 flex flex-col gap-4">
        <div className="flex items-center gap-5 px-4 py-12 mb-10">
          <div className="bg-sky-600 p-4 rounded-[26px] shadow-2xl shadow-sky-200">
            <Stethoscope className="text-white" size={32} />
          </div>
          <div>
            <span className="text-3xl font-black text-sky-900 tracking-tighter block leading-none">PalliativeAI</span>
            <span className="text-[10px] font-black text-sky-600/60 uppercase tracking-[0.4em] mt-2 block">Peaceful Edition</span>
          </div>
        </div>

        <NavButton active={activeTab === 'list'} onClick={() => setActiveTab('list')} icon={<Users size={22}/>} label="แผงผังหอผู้ป่วย" />
        <NavButton active={activeTab === 'admission'} onClick={() => setActiveTab('admission')} icon={<UserPlus size={22}/>} label="เพิ่มเคสใหม่" />

        {selectedPatient && (
          <div className="mt-16 pt-16 border-t border-sky-100 space-y-4 animate-in fade-in slide-in-from-left-6 duration-500">
            <p className="px-6 text-[10px] font-black uppercase tracking-[0.3em] text-sky-400 mb-2">Patient Care</p>
            <NavButton active={activeTab === 'dashboard'} onClick={() => setActiveTab('dashboard')} icon={<LayoutDashboard size={22}/>} label="แดชบอร์ด" />
            <NavButton active={activeTab === 'assessment'} onClick={() => setActiveTab('assessment')} icon={<Activity size={22}/>} label="ประเมินอาการ" />
            <NavButton active={activeTab === 'aftercare'} onClick={() => setActiveTab('aftercare')} icon={<HeartHandshake size={22}/>} label="การดูแลระยะท้าย" />
          </div>
        )}
      </nav>

      {/* Main Content Area */}
      <main className="flex-1 overflow-y-auto p-10 md:p-20">
        <div className="max-w-7xl mx-auto">
          {renderContent()}
        </div>
      </main>
    </div>
  );
};

// Root element mounting
const rootElement = document.getElementById('root');
if (rootElement) {
  const root = createRoot(rootElement);
  root.render(
    <React.StrictMode>
      <PatientProvider>
        <AppContent />
      </PatientProvider>
    </React.StrictMode>
  );
}
